import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

async function compareRoles(question) {
  // Default prompt — no role
  const defaultResponse = await client.messages.create({
    model: "claude-opus-4-5",
    max_tokens: 512,
    messages: [{ role: "user", content: question }],
  });

  // Security engineer role
  const securityResponse = await client.messages.create({
    model: "claude-opus-4-5",
    max_tokens: 512,
    system:
      "You are a senior application security engineer specializing in web API security.",
    messages: [{ role: "user", content: question }],
  });

  return {
    default: defaultResponse.content[0].text,
    security: securityResponse.content[0].text,
  };
}

const question =
  "Our API accepts a user-supplied filename parameter and reads that file from disk. Is this safe?";

compareRoles(question).then(({ default: def, security }) => {
  console.log("=== Default response ===");
  console.log(def);
  console.log("\n=== Security engineer response ===");
  console.log(security);
});
// The security engineer response will name path traversal attacks,
// provide CVE context, and suggest specific mitigations — not just
// "it depends on your implementation".
